#include <stdio.h>
#define READ  4
#define WRITE 2
#define EXEC  1
int set_flag(int flags, int bit)   { return flags | bit; }
int clear_flag(int flags, int bit) { return flags & ~bit; }
int has_flag(int flags, int bit)   { return (flags & bit) != 0; }
void print_perms(int flags) {
    printf("%c%c%c\n",
        has_flag(flags, READ)  ? 'r' : '-',
        has_flag(flags, WRITE) ? 'w' : '-',
        has_flag(flags, EXEC)  ? 'x' : '-');
}
int main(void) {
    int perms = 0;
    perms = set_flag(perms, READ | WRITE);
    print_perms(perms);
    perms = set_flag(perms, EXEC);
    print_perms(perms);
    perms = clear_flag(perms, WRITE);
    print_perms(perms);
    printf("Has READ: %d\n", has_flag(perms, READ));
    return 0;
}

